class SummaryRanges {

    private TreeSet<Integer> set;

    public SummaryRanges() {
        set = new TreeSet<>();
    }

    public void addNum(int value) {
        set.add(value);
    }

    public int[][] getIntervals() {
        int size = set.size();
        int[][] intervals = new int[size][2];
        int index = 0;
        Integer prev = null;
        for (Integer num : set) {
            if (prev == null || num != prev + 1) {
                intervals[index][0] = num;
                intervals[index][1] = num;
                index++;
            } else {
                intervals[index - 1][1] = num;
            }
            prev = num;
        }
        return Arrays.copyOfRange(intervals, 0, index);
    }
}
```

